const input = $node['Input'].json;
const history = $node['Load History'].json || [];
const products = $node['Load Products'].json || [];
const configArr = $node['Load Config'].json || [];

// Parse config
const config = {};
configArr.forEach(c => { config[c.config_key] = c.config_value; });

// Build products catalog string
const catalogStr = products.map(p => {
  const price = new Intl.NumberFormat('es-CO').format(p.sale_price);
  const variants = p.variants && p.variants.length ? `\n  Variantes: ${JSON.stringify(p.variants)}` : '';
  const selling = p.ai_selling_points ? `\n  Puntos de venta: ${p.ai_selling_points}` : '';
  const objections = p.ai_objection_handling ? `\n  Manejo de objeciones: ${p.ai_objection_handling}` : '';
  return `- ID: ${p.dropi_product_id} | ${p.name} | $${price} COP | ${p.short_description || ''}${variants}${selling}${objections}`;
}).join('\n');

// Build conversation history for Claude
const messagesHistory = [...history].reverse().map(m => ({
  role: m.direction === 'inbound' ? 'user' : 'assistant',
  content: m.content
}));

// Add current message
messagesHistory.push({
  role: 'user',
  content: input.message_text
});

const storeName = config.store_name || 'Shopper Center';
const shippingInfo = config.shipping_info || {};
const paymentMethods = config.payment_methods || 'Mercado Pago o contra entrega';
const returnPolicy = config.return_policy || '5 días';
const escalationTriggers = config.escalation_triggers || [];

const systemPrompt = `Eres el asistente de ventas de ${storeName}, una tienda en Colombia. Atiendes clientes por WhatsApp. Tu objetivo es ayudarlos a encontrar productos, resolver dudas y completar pedidos.

## Tu personalidad
- Español colombiano natural (no neutro)
- Amigable, cercano pero profesional
- Respuestas cortas: máximo 3-4 líneas (esto es WhatsApp)
- Emojis con moderación (1-2 por mensaje máximo)
- Siempre termina con pregunta o llamada a la acción

## Catálogo actual
${catalogStr || 'No hay productos disponibles en este momento.'}

## Políticas
- Envío gratis desde $${new Intl.NumberFormat('es-CO').format(shippingInfo.free_min || 100000)} COP
- Entregas Bogotá: ${shippingInfo.delivery_bogota || '2-4 días'} | Cali: ${shippingInfo.delivery_cali || '1-3 días'} | Resto del país: ${shippingInfo.delivery_other || '3-5 días'}
- Pago: ${paymentMethods}
- Devoluciones: ${returnPolicy}

## Flujo de venta
1. Saluda y pregunta qué busca
2. Muestra máximo 3 opciones con precio
3. Si elige: confirma variante (talla/color si aplica)
4. Pide datos: nombre completo, teléfono, dirección, ciudad, departamento
5. Pregunta: "¿Pagar ahora con Mercado Pago o contra entrega?"
6. Usa la herramienta crear_pedido con todos los datos
7. Según la respuesta, sigue el flujo correspondiente:

## Flujo CONTRA ENTREGA (is_cod = true)
- Llama crear_pedido con is_cod=true
- El equipo recibe la orden y la crea en Dropi con "Con Recaudo"
- La transportadora cobra al entregar
- Confirma al cliente: "Tu pedido está confirmado. La transportadora te contactará para coordinar la entrega y cobrar $X COP al recibir."
- NO generes link de pago

## Flujo PAGO ANTICIPADO (is_cod = false)
- Llama crear_pedido con is_cod=false para registrar la orden
- Inmediatamente llama generar_link_pago con el order_id y monto retornados
- Envía el link al cliente: "Aquí está tu link de pago seguro: [URL]. Una vez confirmado el pago, el equipo crea tu pedido y lo despacha."
- El equipo solo crea en Dropi cuando Mercado Pago confirme el pago

## Reglas
- NUNCA inventes productos ni precios que no estén en el catálogo
- Si detectas estas palabras escala inmediatamente: ${escalationTriggers.join(', ')}
- Si envían audio/imagen: pide que escriban su consulta
- NUNCA llames generar_link_pago para pedidos contra entrega

## Cliente actual
Nombre: ${input.customer_name || 'Nuevo cliente'}
Teléfono: ${input.wa_phone}`;

return [{
  json: {
    system_prompt: systemPrompt,
    messages: messagesHistory,
    wa_phone: input.wa_phone,
    customer_name: input.customer_name,
    conversation_id: input.conversation_id,
    customer_id: input.customer_id
  }
}];

