const response = $input.first().json;
const content = response.content || [];

const toolUse = content.find(c => c.type === 'tool_use');
const textBlock = content.find(c => c.type === 'text');

if (toolUse) {
  return [{
    json: {
      has_tool: true,
      tool_name: toolUse.name,
      tool_input: toolUse.input,
      tool_use_id: toolUse.id,
      text_before_tool: textBlock?.text || null,
      wa_phone: $node['Build Prompt'].json.wa_phone,
      customer_name: $node['Build Prompt'].json.customer_name,
      conversation_id: $node['Build Prompt'].json.conversation_id,
      customer_id: $node['Build Prompt'].json.customer_id,
      messages: $node['Build Prompt'].json.messages,
      system_prompt: $node['Build Prompt'].json.system_prompt
    }
  }];
}

const replyText = textBlock?.text || 'Disculpa, hubo un error. ¿Puedes repetir tu mensaje?';

return [{
  json: {
    has_tool: false,
    reply: replyText,
    wa_phone: $node['Build Prompt'].json.wa_phone,
    conversation_id: $node['Build Prompt'].json.conversation_id
  }
}];

const input = $input.first().json;
const toolInput = typeof input.tool_input === 'string' ? JSON.parse(input.tool_input) : input.tool_input;

const subtotal = toolInput.items.reduce((sum, item) => sum + (item.unit_price * item.quantity), 0);

const nameParts = (toolInput.customer_name || '').trim().split(' ');
const firstName = nameParts[0] || '';
const lastName = nameParts.slice(1).join(' ') || '-';

return [{
  json: {
    conversation_id: input.conversation_id,
    customer_id: input.customer_id,
    customer_name: toolInput.customer_name,
    first_name: firstName,
    last_name: lastName,
    customer_phone: toolInput.customer_phone,
    address: toolInput.address,
    city: toolInput.city,
    department: toolInput.department,
    email: toolInput.email || '',
    items: toolInput.items,
    is_cod: toolInput.is_cod,
    subtotal,
    total: subtotal
  }
}];

