const order = $node['Insert Order'].json[0];
return [{
  json: {
    order_id: order.id,
    order_number: order.order_number,
    total: order.total,
    is_cod: order.is_cod,
    status: order.status
  }
}];

const input = $input.first().json;
const toolInput = typeof input.tool_input === 'string' ? JSON.parse(input.tool_input) : input.tool_input;
return [{
  json: {
    order_id: toolInput.order_id,
    amount: toolInput.amount,
    description: toolInput.description,
    wa_phone: input.wa_phone
  }
}];

const mpData = $node['Create MP Preference'].json;
return [{
  json: {
    payment_url: mpData.init_point,
    preference_id: mpData.id
  }
}];

const prev = $node['Which Tool?'].json;
let toolResult = '';

if (prev.tool_name === 'crear_pedido') {
  const orderData = $input.first().json;
  toolResult = JSON.stringify({ success: true, order_id: orderData.order_id, order_number: orderData.order_number, total: orderData.total, is_cod: orderData.is_cod, message: 'Pedido creado exitosamente' });
} else if (prev.tool_name === 'generar_link_pago') {
  const mpData = $input.first().json;
  toolResult = JSON.stringify({ success: true, payment_url: mpData.payment_url, message: 'Link de pago generado' });
} else if (prev.tool_name === 'buscar_productos') {
  const products = $input.first().json;
  toolResult = JSON.stringify(Array.isArray(products) ? products : [products]);
} else if (prev.tool_name === 'escalar_a_humano') {
  toolResult = JSON.stringify({ success: true, message: 'Conversación escalada a agente humano' });
} else if (prev.tool_name === 'consultar_pedido') {
  const orders = $input.first().json;
  const orderList = Array.isArray(orders) ? orders : [];
  toolResult = JSON.stringify(orderList.length > 0 ? orderList : { message: 'No se encontraron pedidos para este número' });
} else {
  toolResult = JSON.stringify({ success: false, message: 'Herramienta no reconocida' });
}

const messages = [...prev.messages,
  { role: 'assistant', content: [{ type: 'tool_use', id: prev.tool_use_id, name: prev.tool_name, input: prev.tool_input }] },
  { role: 'user', content: [{ type: 'tool_result', tool_use_id: prev.tool_use_id, content: toolResult }] }
];

return [{
  json: {
    system_prompt: prev.system_prompt,
    messages,
    wa_phone: prev.wa_phone,
    conversation_id: prev.conversation_id
  }
}];

const response = $input.first().json;
const replyText = response.content?.find(c => c.type === 'text')?.text || 'Listo! ¿Hay algo más en que te pueda ayudar?';
return [{
  json: {
    reply: replyText,
    wa_phone: $node['Build Tool Result'].json.wa_phone,
    conversation_id: $node['Build Tool Result'].json.conversation_id
  }
}];

